"use client";
import { foundItems } from '../data/founditem';
import { lostItems } from '../data/lostitem';
import Card from './card';



const ItemSection = ({lostOrFound}) => {
    const itemToShow= lostOrFound==="lost"? lostItems: foundItems;
    const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6; // show 6 items per page

  // Calculate pagination
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = itemToShow.slice(indexOfFirstItem, indexOfLastItem);

  const totalPages = Math.ceil(itemToShow.length / itemsPerPage);
  return (
    <div className='bg-[#F9F8F6] flex justify-center items-start flex-wrap gap-6 px-6 pt-10'>
       { itemToShow.map((item)=>(
        <Card key={item.id} item={item}/>
        ))
    }
      
    </div>
  )
}

export default ItemSection
